expected.dbQuery:
db.transactions.aggregate([
  { $unwind: "$transactions" },
  { $match: {
      "transactions.date": { $gte: new Date("2014-01-01"), $lte: new Date("2016-12-31") }
  }},
  { $group: {
      _id: "$account_id",
      transaction_count: { $sum: 1 }
  }},
  { $sort: { transaction_count: -1 } },
  { $limit: 5 },
  { $project: {
      _id: 0,
      account_id: "$_id",
      transaction_count: 1
  }}
])

db.sales.find({
  purchaseMethod: 'Online',
  storeLocation: 'Austin',
  saleDate: {
    $gte: new Date('2017-09-01T00:00:00Z'),
    $lt: new Date('2017-10-01T00:00:00Z')
  }
}, {
  'customer.satisfaction': 1,
  _id: 0
})

db.sales.aggregate([
  {
    $match: {
      storeLocation: 'Denver',
      saleDate: {
        $gte: new Date('2017-01-01T00:00:00Z'),
        $lte: new Date('2017-03-31T23:59:59Z')
      }
    }
  },
  {
    $group: {
      _id: null,
      averageSatisfaction: { $avg: '$customer.satisfaction' }
    }
  },
  {
    $project: {
      _id: 0,
      averageSatisfaction: 1
    }
  }
])

db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: new Date('2017-12-01'),
        $lt: new Date('2018-01-01')
      }
    }
  },
  {
    $group: {
      _id: "$storeLocation",
      totalSales: { $sum: 1 }
    }
  },
  {
    $sort: { totalSales: -1 }
  },
  {
    $limit: 1
  },
  {
    $project: { _id: 1 }
  },
  {
    $lookup: {
      from: "sales",
      let: { location: "$_id" },
      pipeline: [
        {
          $match: {
            saleDate: {
              $gte: new Date('2017-12-01'),
              $lt: new Date('2018-01-01')
            }
          }
        },
        {
          $match: {
            $expr: { $eq: ["$storeLocation", "$$location"] }
          }
        },
        {
          $unwind: "$items"
        },
        {
          $group: {
            _id: "$items.name",
            quantitySold: { $sum: "$items.quantity" }
          }
        },
        {
          $sort: { quantitySold: -1 }
        },
        {
          $limit: 10
        },
        {
          $project: {
            _id: 0,
            itemName: "$_id",
            quantitySold: 1
          }
        }
      ],
      as: "topItems"
    }
  },
  {
    $unwind: "$topItems"
  },
  {
    $replaceRoot: { newRoot: "$topItems" }
  }
]);

db.sales.aggregate([
  {
    $match: {
      storeLocation: { $in: ['New York', 'San Francisco'] },
      saleDate: { $gte: new Date('2017-12-01'), $lte: new Date('2017-12-31') }
    }
  },
  {
    $unwind: '$items'
  },
  {
    $match: {
      'items.price': { $gt: 900 }
    }
  },
  {
    $group: {
      _id: '$customer.email'
    }
  },
  {
    $project: {
      email: '$_id',
      _id: 0
    }
  }
])

db.sales.aggregate([
  {
    $match: {
      storeLocation: "Austin",
      saleDate: {
        $gte: new Date("2017-11-01T00:00:00.000Z"),
        $lt: new Date("2017-12-01T00:00:00.000Z")
      },
      purchaseMethod: { $in: ["Online", "In store"] }
    }
  },
  {
    $group: {
      _id: "$purchaseMethod",
      averageSatisfaction: { $avg: "$customer.satisfaction" }
    }
  },
  {
    $project: {
      _id: 0,
      purchaseMethod: "$_id",
      averageSatisfaction: 1
    }
  }
])

