db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: new Date("2017-12-01T00:00:00Z"),
        $lt: new Date("2018-01-01T00:00:00Z")
      }
    }
  },
  {
    $unwind: "$items"
  },
  {
    $group: {
      _id: "$items.name",
      totalQuantitySold: { $sum: "$items.quantity" }
    }
  },
  {
    $sort: { totalQuantitySold: -1 }
  },
  {
    $limit: 5
  },
  {
    $project: {
      _id: 0,
      itemName: "$_id",
