db.planets.aggregate([
  {
    $match: {
      'surfaceTemperatureC.mean': {
        $gte: 50,
        $lte: 150
      }
    }
  },
  {
    $group: {
      _id: '$mainAtmosphere',
      count: { $sum: 1 },
      planets: { $push: { name: '$name', surfaceTemperatureC: '$surfaceTemperatureC.mean' } }
    }
  },
  {
    $match: {
      count: 1
    }
  },
  {
    $project: {
      _id: 0,
      mainAtmosphere: '$_id',
      planet: { $arrayElemAt: ['$planets', 0] }
    }
  },
  {
    $project: {
      name: '$planet.name',
      mainAtmosphere: '$mainAtmosphere',
      'surfaceTemperatureC.mean': '$planet.surfaceTemperatureC'
    }
  }
])

db.sales.aggregate([
  {
    $match: {
