db.listingsAndReviews.find({
  property_type: 'Apartment',
  beds: { $gte: 2 },
  'address.location': {
    $geoWithin: {
      $centerSphere: [[151.2153, -33.8572], 1 / 3963.2] // 1 mile radius
    }
  }
}, {
  listing_url: 1,
  name: 1,
  property_type: 1,
  beds: 1,
  'address.location.coordinates': 1
})

db.planets.find(
  { hasRings: true },
  { name: 1, mainAtmosphere: 1, 'surfaceTemperatureC.mean': 1, _id: 0 }
).sort({ name: 1 })

const chinatownCoordinates = db.neighborhoods.findOne({name: 'Chinatown'}).geometry.coordinates;
db.restaurants.find({
  cuisine: 'Italian',
  'address.coord': {
    $geoWithin: {
      $geometry: {
        type: 'Polygon',
        coordinates: chinatownCoordinates
      }
    }
  }
}, {
  name: 1,
  address: 1,
  _id: 0
})

db.listingsAndReviews.find(
  { property_type: 'Apartment' },
  { _id: 1, name: 1, cleaning_fee: 1, property_type: 1, room_type: 1 }
).sort({ cleaning_fee: -1 }).limit(10)

db.listingsAndReviews.find({
  room_type: { $in: ['Private room', 'Shared room'] }
}, {
  _id: 1,
  name: 1,
  cleaning_fee: 1,
  property_type: 1,
  room_type: 1
}).sort({
  cleaning_fee: -1
}).limit(10)

const earthMeanTemperature = db.planets.findOne({ name: 'Earth' }, { 'surfaceTemperatureC.mean': 1 }).surfaceTemperatureC.mean;
db.planets.find(
  { 'surfaceTemperatureC.mean': { $gte: earthMeanTemperature - 5, $lte: earthMeanTemperature + 5 } },
  { name: 1, 'surfaceTemperatureC.mean': 1, _id: 0 }
);

const chinatownGeometry = db.neighborhoods.findOne({name: 'Chinatown'}).geometry;
db.restaurants.aggregate([
  {
    $match: {
      'address.coord': {
        $geoWithin: {
          $geometry: chinatownGeometry
        }
      }
    }
  },
  {
    $group: {
      _id: '$cuisine',
      count: {$sum: 1}
    }
  },
  {
    $sort: {count: -1}
  },
  {
    $limit: 5
  },
  {
    $project: {
      _id: 0,
      cuisine: '$_id',
      count: 1
    }
  }
])

db.listingsAndReviews.find({
