db.movies.aggregate([
  {
    $match: {
      countries: "Japan",
      released: {
        $gte: new Date("2005-01-01"),
        $lte: new Date("2015-12-31")
      }
    }
  },
  {
    $project: {
      title: 1,
      _id: 0
    }
