db.planets.aggregate([
  {
    $match: {
      "surfaceTemperatureC.max": { $ne: null },
      "surfaceTemperatureC.min": { $ne: null }
    }
  },
  {
    $addFields: {
      tempDifference: {
        $subtract: ["$surfaceTemperatureC.max", "$surfaceTemperatureC.min"]
      }
    }
  },
  {
    $match: {
      tempDifference: { $gt: 100 }
    }
  },
  {
    $project: {
      _id: 0,
      name: 1,
      "surfaceTemperatureC.min": 1,
      "surfaceTemperatureC.max": 1
    }
  }
])

const coronaNeighborhood = db.neighborhoods.findOne({ name: 'Corona' });
db.restaurants.find({
