db.restaurants.aggregate([
  {
    $match: {
      'borough': 'Queens',
      'address.zipcode': '11368'
    }
  },
  {
    $unwind: '$grades'
  },
  {
    $group: {
      _id: null,
      avgScore: { $avg: '$grades.score' },
      scores: { $push: '$grades.score' }
    }
  },
  {
    $project: {
      _id: 0,
      variance: {
        $let: {
          vars: {
            avgScore: '$avgScore'
          },
          in: {
            $divide: [
              {
                $sum: {
                  $map: {
                    input: '$scores',
                    as: 'score',
                    in: { $pow: [{ $subtract: ['$$score', '$$avgScore'] }, 2] }
                  }
                }
              },
              { $size: '$scores' }
            ]
          }
        }
      }
    }
  }
])

