db.planets.aggregate([
  {
    $match: {
      mainAtmosphere: {
        $in: ["N", "O2", "Ar"]
      }
    }
  },
  {
    $project: {
      name: 1,
      mainAtmosphere: 1,
      _id: 0
    }
  },
  {
    $addFields: {
      matchedElements: {
        $filter: {
          input: "$mainAtmosphere",
          cond: { $in: ["$$this", ["N", "O2", "Ar"]] }
        }
      }
    }
  },
  {
    $match: {
      "matchedElements.1": { $exists: true }
    }
  },
