      _id: "$storeLocation",
      totalSales: {
        $sum: {
          $multiply: ["$items.price", "$items.quantity"]
        }
      }
    }
  },
  {
    $sort: {
      totalSales: -1
    }
  },
  {
    $limit: 5
  },
  {
    $project: {
      _id: 0,
      storeLocation: "$_id",
      totalSales: 1
    }
  }
])

