db.theaters.aggregate([
  {
    $match: {
      "location.address.city": "New York",
      "location.address.state": "NY"
    }
  },
  {
    $lookup: {
      from: "sessions",
      localField: "_id",
      foreignField: "user_id", // Assuming user_id corresponds to the theater
      as: "sessions"
    }
  },
  {
    $addFields: {
      sessionCount: { $size: "$sessions" }
    }
  },
  {
    $sort: { sessionCount: -1 }
  },
  {
    $project: {
      theaterId: 1,
      "location.address.city": 1,
      "location.address.state": 1,
      _id: 0
    }
  }
])

db.sales.aggregate([
  {
    $match: {
      storeLocation: "New York",
      saleDate: {
        $gte: new Date("2017-12-28T00:00:00Z"),
        $lt: new Date("2017-12-29T00:00:00Z")
      }
    }
  },
  {
    $unwind: "$items"
  },
  {
    $group: {
      _id: "$_id",
      transactionTotal: {
        $sum: {
          $multiply: ["$items.price", "$items.quantity"]
        }
      }
    }
  },
  {
    $group: {
      _id: null,
      totalSales: {
        $sum: "$transactionTotal"
      },
      transactionCount: {
        $sum: 1
      }
    }
  },
  {
    $project: {
      _id: 0,
      totalSales: 1,
      transactionCount: 1,
      averageTransactionValue: {
        $cond: {
          if: { $eq: ["$transactionCount", 0] },
          then: 0,
          else: { $divide: ["$totalSales", "$transactionCount"] }
        }
      }
    }
  }
])

